import React, { useState } from "react";
import "../styles/practice.css"; // Ensure this path is correct

const practiceAreas = [
    { title: "Intellectual Property", content: "INTELLECTUAL PROPERTY (IP) PROSECUTION & PORTFOLIO MANAGEMENT\n\nWe are experienced in all aspects of establishing, managing, and protecting all IP aspects including, trademarks, patents, industrial designs, and copyrights. We combine practical, efficient advice with cost-effective legal services for a broad range of IP issues because we understand that your IP are valuable assets that help define your unique corporate identity. We have handled IP Portfolios on behalf of a broad range of clients, including software industries, food and beverages, education services, fashions, IT companies, telecommunications, financial services, pharmacies, and consumer products. We have been closely working and collaborating with IP Agents in Singapore, Malaysia, Indonesia, Thailand, the Philippines, Vietnam, and Myanmar so that we will be able to serve our clients in all ten ASEAN countries, as well as other jurisdictions such as Japan, Hong Kong, and Australia.\n\nINTELLECTUAL PROPERTY (IP) LITIGATION & ENFORCEMENT\n\nWe work closely with clients in the development of effective enforcement strategies for their IP portfolios and in the defense of enforcement actions. We have a strong anti-counterfeiting team where since our earliest establishment we have been retained by several world’s largest software manufacturers to carry out software license anti-counterfeiting projects in Indonesia. In addition, we have experience in representing clients as plaintiff and defendant in trademark cancellation cases before the Commercial Court and the Supreme Court." },
    { title: "Suspension of Payment/Bankruptcy Law & Debt Recovery", content: "DEBT RECOVERY A&CO’s litigation team has extensive experiences in providing pieces of legal advice and litigation services in relation to debt recovery. We offer the clients efficiency, together with the skills & expertise of a professional legal team. Before initiating legal actions, we provide credit control services such as issuing letters of demand before the legal actions, company’s background search service, credit reports and status reports.BANKRUPTCY LAWWe provide advice on Bankruptcy Law and proceedings in the Commercial Court. In addition, we have represented clients as applicants, creditors or debtors in bankruptcy and suspension of debt payments applications in the Commercial and Supreme Courts, and have had considerable experiences in representing multinational finance & leasing companies, insurance companies, multinational electronic manufacturer companies, land & property developers and IT developer companies at creditors’ meetings during the periods of suspension of payments and bankruptcy." },
    { title: "Corporate and Investment", content: "Content for Corporate and Investment" },
    { title: "Mergers & Acquisitions", content: "Content for Mergers & Acquisitions" },
    { title: "Antitrust & Competition Law", content: "Content for Antitrust & Competition Law" },
    { title: "Dispute Resolution", content: "Content for Dispute Resolution" },
    { title: "Family Law", content: "Content for Family Law" },
    { title: "Private Data Protection", content: "Content for Private Data Protection" }
];

const PracticeAreas = () => {
    const [activeIndex, setActiveIndex] = useState(0);

    return (
        <div className="practice-container">
            <div className="practice-list">
                <ul>
                    {practiceAreas.map((area, index) => (
                        <li
                            key={index}
                            className={index === activeIndex ? "active" : ""}
                            onClick={() => setActiveIndex(index)}
                        >
                            {area.title}
                        </li>
                    ))}
                </ul>
            </div>
            <div className="practice-text">
                <h2>{practiceAreas[activeIndex].title}</h2>
                <p>{practiceAreas[activeIndex].content}</p>
            </div>
        </div>
    );
};

export default PracticeAreas;
